const KickerLabel: React.FC<{
  children: React.ReactNode;
  className?: string;
}> = ({ children, className }) => (
  <div className={cn("flex items-center gap-3 mb-6", className)}>
    <span className="text-[#C9A87C] text-[8px] leading-none">&#x25C6;</span>
    <span className="text-[11px] font-semibold uppercase tracking-[0.2em] text-foreground/50 leading-none">
      {children}
    </span>
    <span className="text-[#C9A87C] text-[8px] leading-none">&#x25C6;</span>
  </div>
);

const IntroWord: React.FC<{
  word: string;
  index: number;
  total: number;
  progress: MotionValue<number>;
}> = ({ word, index, total, progress }) => {
  const start = (index / total) * 0.9;
  const end = ((index + 1) / total) * 0.9;
  const opacity = useTransform(progress, [start, end], [0.12, 1]);

  return (
    <motion.span style={{ opacity }} className="inline-block mr-[0.32em]">
      {word}
    </motion.span>
  );
};

const StickyImageFrame: React.FC<{
  blocks: StoryBlock[];
  activeIdx: number;
}> = ({ blocks, activeIdx }) => (
  <div className="relative w-full max-w-[460px] mx-auto">
    <div
      className="absolute inset-0 rounded-[22px]"
      style={{
        background: "rgba(212,184,146,0.18)",
        transform: "rotate(-7deg) translate(16px, 16px)",
      }}
    />
    <div
      className="absolute inset-0 rounded-[22px]"
      style={{
        background: "rgba(201,168,124,0.10)",
        transform: "rotate(-5deg) translate(8px, 8px)",
      }}
    />
    <div
      className="relative aspect-[4/5] rounded-[22px] overflow-hidden ring-1 ring-black/[0.04]"
      style={{
        transform: "rotate(-3deg)",
        boxShadow: "0 30px 60px -15px rgba(0,0,0,0.25)",
      }}
    >
      {blocks.map((b, i) => (
        <img
          key={i}
          src={b.image}
          alt=""
          className={cn(
            "absolute inset-0 w-full h-full object-cover transition-all duration-700 ease-in-out will-change-[opacity,transform]",
            activeIdx === i
              ? "opacity-100 scale-100"
              : "opacity-0 scale-[1.04]"
          )}
          style={{ zIndex: activeIdx === i ? 2 : 1 }}
          loading={i === 0 ? "eager" : "lazy"}
        />
      ))}
    </div>
  </div>
);

const MobileImageFrame: React.FC<{ src: string }> = ({ src }) => (
  <div className="lg:hidden mb-10">
    <div className="relative max-w-xs mx-auto">
      <div
        className="absolute inset-0 rounded-[16px]"
        style={{
          background: "rgba(251, 251, 249, 1)",
          transform: "rotate(-5deg) translate(8px, 8px)",
        }}
      />
      <div
        className="relative aspect-[4/5] rounded-[16px] overflow-hidden shadow-xl ring-1 ring-black/5"
        style={{ transform: "rotate(-2deg)" }}
      >
        <img
          src={src}
          alt=""
          className="w-full h-full object-cover"
          loading="lazy"
        />
      </div>
    </div>
  </div>
);

