export const StoryIntroSection: React.FC = () => {
  const introRef = useRef<HTMLDivElement>(null);

  const { scrollYProgress: introProgress } = useScroll({
    target: introRef,
    offset: ["start 0.85", "end 0.15"],
  });

  const words = INTRO_TEXT.split(" ");

  return (
    <section className="bg-[#FBFAF9]">
      <div
        ref={introRef}
        className="flex flex-col items-center justify-center px-6 md:px-12 pt-[5.6rem] pb-12 lg:pt-[7rem] lg:pb-16 relative"
        style={{ minHeight: "70vh" }}
      >
        <div
          className="text-center max-w-[56rem] mx-auto"
          style={{ fontSize: "50px" }}
        >
          <KickerLabel className="justify-center mb-10 lg:mb-14">
            {SECTION_KICKER}
          </KickerLabel>

          <H2
            className="font-normal"
            style={{
              fontFamily: "'LLIvory', serif",
              fontWeight: 400,
              fontSize: "48px",
              lineHeight: "60px",
              color: "#000000",
              fontStyle: "normal",
              display: "flex",
              flexWrap: "wrap",
              justifyContent: "center",
            }}
          >
            {words.map((w, i) => (
              <IntroWord
                key={i}
                word={w}
                index={i}
                total={words.length}
                progress={introProgress}
              />
            ))}
          </H2>
        </div>

        <PalmSVG className="w-20 sm:w-24 lg:w-28 mt-10 lg:mt-14 text-foreground/70" />
      </div>
    </section>
  );
};

export const StoryBlocksSection: React.FC = () => {
  const blockRefs = useRef<(HTMLDivElement | null)[]>([]);
  const [activeIdx, setActiveIdx] = useState(0);

  useEffect(() => {
    const observers: IntersectionObserver[] = [];

    blockRefs.current.forEach((el, i) => {
      if (!el) return;
      const obs = new IntersectionObserver(
        ([entry]) => {
          if (entry.isIntersecting) setActiveIdx(i);
        },
        { threshold: 0.35, rootMargin: "-20% 0px -20% 0px" }
      );
      obs.observe(el);
      observers.push(obs);
    });

    return () => observers.forEach((o) => o.disconnect());
  }, []);

  return (
    <section className="bg-background">
      <div className="relative">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="grid lg:grid-cols-[44%_56%] gap-8 lg:gap-20 lg:items-start">
            <div className="hidden lg:block lg:sticky lg:top-[12vh]">
              <StickyImageFrame
                blocks={STORY_BLOCKS}
                activeIdx={activeIdx}
              />
            </div>

            <div>
              {STORY_BLOCKS.map((block, i) => (
                <div
                  key={i}
                  ref={(el) => {
                    blockRefs.current[i] = el;
                  }}
                  className={cn(
                    "flex items-center",
                    i === 0 ? "min-h-[75vh]" : "min-h-[90vh]",
                    i === STORY_BLOCKS.length - 1 && "pb-24 lg:pb-32"
                  )}
                >
                  <div className="max-w-lg py-12 lg:py-20 lg:pl-4">
                    <MobileImageFrame src={block.image} />

                    <KickerLabel>{block.kicker}</KickerLabel>

                    <h3 className="font-display text-[1.75rem] sm:text-[2rem] md:text-[2.25rem] lg:text-[3rem] font-normal text-foreground leading-[1.15] mb-5 tracking-tight">
                      {block.heading}
                    </h3>

                    <p className="text-muted-foreground text-[0.95rem] md:text-[1.05rem] leading-[1.7] max-w-md">
                      {block.body}
                    </p>

                    {block.cta && (
                      <div className="mt-8">
                        <Link href={block.cta.href}>
                          <Button className="bg-primary hover:bg-primary/90 text-white rounded-full pl-7 pr-5 h-12 text-sm font-semibold gap-2 shadow-lg shadow-primary/20 transition-all duration-200 hover:shadow-xl hover:shadow-primary/25 hover:-translate-y-0.5">
                            {block.cta.label}
                            <ArrowRight className="h-4 w-4" />
                          </Button>
                        </Link>
                      </div>
                    )}
                  </div>
                </div>
              ))}
            </div>
          </div>
        </div>
      </div>
    </section>
  );
};

const StoryScrollSection: React.FC = () => (
  <>
    <StoryIntroSection />
    <StoryBlocksSection />
  </>
);

export default StoryScrollSection;
